#include <stdio.h>
#include <pthread.h>
#include <stdatomic.h>

atomic_int counter = 0;

void *increment(void *arg) {
    int id = *(int *)arg;
    for (int i = 0; i < 3; i++) {
        int old = atomic_load(&counter);
        while (!atomic_compare_exchange_strong_explicit(&counter, &old, old + 1,
                     memory_order_seq_cst, memory_order_seq_cst));
        printf("Thread %d: counter = %d\n", id, old + 1);
    }
    return NULL;
}

int main(void) {
    pthread_t t[3];
    int ids[3] = {0, 1, 2};
    for (int i = 0; i < 3; i++) {
        pthread_create(&t[i], NULL, increment, &ids[i]);
        pthread_join(t[i], NULL);
    }
    printf("Final: %d\n", atomic_load(&counter));
    return 0;
}

